// RUN: objc3c -fobjc-version=3 --emit-module SYSATTR06.objcmod --emit-interface SYSATTR06.obji %s
// RUN: objc3c --verify-interface SYSATTR06.objcmod SYSATTR06.obji %s
#define SYS_RESOURCE(CLOSE_FN, INVALID_VALUE) __attribute__((objc_resource(close=CLOSE_FN, invalid=INVALID_VALUE)))
typedef int objc_handle_t;
void close_socket(objc_handle_t socket_fd);
extern objc_handle_t gTrackedSocket SYS_RESOURCE(close_socket, -1);

expect.canonical_interface:
typedef int objc_handle_t;
void close_socket(objc_handle_t socket_fd);
extern objc_handle_t gTrackedSocket __attribute__((objc_resource(close=close_socket, invalid=-1)));
